+            "normal", None, false,
+        );
+    }
+
+    // Run the same paginated query 3 times
+    let mut all_runs: Vec<Vec<i64>> = Vec::new();
+    for _ in 0..3 {
+        let mut collected = Vec::new();
+        let mut cursor: Option<String> = None;
+        loop {
