+                ..default_signals()
+            },
+            HealthLevel::Yellow,
+        ),
+        (
+            "pool_latency_red",
+            HealthSignals {
+                pool_acquire_p95_us: backpressure::red::POOL_ACQUIRE_P95_US + 1,
