+            },
+            HealthLevel::Red,
+        ),
+        // Pool utilization
+        (
+            "pool_util_yellow",
+            HealthSignals {
+                pool_utilization_pct: 70,
+                ..default_signals()
+            },
+            HealthLevel::Yellow,
+        ),
+        (
+            "pool_util_red",
