+                wbq_depth_pct: 50,
+                ..default_signals()
+            },
+            HealthLevel::Yellow,
+        ),
+        (
+            "wbq_depth_red",
+            HealthSignals {
+                wbq_depth_pct: 80,
+                ..default_signals()
+            },
+            HealthLevel::Red,
+        ),
+        // Commit depth
+        (
+            "commit_depth_yellow",
+            HealthSignals {
+                commit_depth_pct: 50,
+                ..default_signals()
+            },
+            HealthLevel::Yellow,
+        ),
+        (
+            "commit_depth_red",
+            HealthSignals {
+                commit_depth_pct: 80,
+                ..default_signals()
+            },
+            HealthLevel::Red,
+        ),
+        // Sustained over-80 durations
+        (
+            "pool_sustained_300s",
+            HealthSignals {
+                pool_over_80_for_s: 300,
+                ..default_signals()
+            },
+            HealthLevel::Red,
+        ),
+        (
+            "wbq_sustained_300s",
+            HealthSignals {
+                wbq_over_80_for_s: 300,
+                ..default_signals()
+            },
+            HealthLevel::Red,
+        ),
+        (
+            "commit_sustained_300s",
+            HealthSignals {
+                commit_over_80_for_s: 300,
+                ..default_signals()
+            },
+            HealthLevel::Red,
+        ),
+        // Compound: yellow + red → Red wins
+        (
+            "compound_yellow_plus_red",
+            HealthSignals {
+                pool_acquire_p95_us: backpressure::yellow::POOL_ACQUIRE_P95_US + 1,
+                wbq_depth_pct: 80,
+                ..default_signals()
+            },
