+
+    // Case 9: Explicit governor_tier without degraded trigger → None
+    let explain_tier_only = make_explain("legacy", vec!["governor_tier:tight".to_string()], false);
+    let d = derive_diagnostics(Some(&explain_tier_only));
+    assert!(
+        d.is_none(),
